  ('police-8b7f1efc-moex-00250', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據警察職權行使法第6條規定，警察於公共場所或合法進入之場所，得對於下列何者之人查證 其身分？', '["滯留於有事實足認有陰謀、預備、著手實施重大犯罪或有人犯藏匿之處所者", "合理懷疑其有違反行政罰之虞者", "合理懷疑其對已發生之犯罪或即將發生之犯罪知情者", "有事實足認為防止其本人或他人生命、身體及財產之具體危害，有查證其身分之必要者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00251', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '關於警察勤務制度、事權及法令之規定，下列何者正確？', '["警察勤務制度，由中央立法並執行，不能交由直轄市、縣（市）執行", "警察勤務制度，指警察業務之單位組合勤務方式之基本原則事項", "直轄市警察勤務機構設置、裁併及勤務之實施事項，由中央立法，再交由直轄市執行", "警察勤務條例之規定，於各專業警察機關執行各該專屬勤務時準用之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00252', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '公共安全、秩序維護與危害防止任務不再專由形式的警察組織行使，其他機關依據職權法規分別 行使命令強制權力，此為何者警政發展？', '["警察權集中化", "警察權專業化", "警察權分散化", "警察權兩極化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
