  ('police-8b7f1efc-moex-00254', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '關於警察權的敘述，下列何者正確？', '["民主法治政體，警察權力的基礎，源自統治者實施統治權的作用", "警察法第3條規定的警察事權，為中央與地方機關警察權限的橫向分配", "專由形式意義的警察機關行使的權力方法，稱為警察職權", "警察裁量是在法的空間內所為的自由決定，如有裁量瑕疵，係由行政機關自行監督審查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00255', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據執行巡邏勤務中盤查盤檢人車作業程序規定，警察執行巡邏勤務中盤查盤檢人車時，受盤查 人如當場陳述理由，表示異議，下列作業內容何者錯誤？', '["異議有理由，警察立即停止盤查盤檢，當場放行，或更正執行行為", "異議無理由，則繼續執行", "受盤查人請求時，填寫警察行使職權民眾異議紀錄表一式三聯", "將表示異議者帶往勤務處所，製作警察行使職權民眾異議筆錄一式三聯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00256', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '關於地方政府警察局勤務實施細則之敘述，下列何者正確？', '["臺中市政府警察局勤務實施細則，由內政部警政署擬定", "臺北市政府警察局勤務實施細則，陳報臺北市政府核准施行", "嘉義縣警察局勤務實施細則，陳報內政部警政署核准施行", "臺南市政府警察局勤務實施細則的法律依據為警察職權行使法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
